const body = $json.body || {};
const email = (body.email || '').trim();
const name = (body.name || '').trim();
const company = (body.company || '').trim();
const role = (body.role || '').trim();
const problem_description = (body.problem_description || '').trim();
const phone = (body.phone || '').trim();
const lead_id = 'lead_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6);
const valid = !!(email && name && company && problem_description);
return [{ json: { valid, lead_id, email, name, company, role, phone, problem_description } }];

const clearbitResp = $input.first().json;
const lead = $('Extract and Validate Lead Fields').first().json;

// Detect Clearbit failure: error object, message field, or missing both metrics and domain
const clearbit_failed = !!(clearbitResp.error || clearbitResp.message || (!clearbitResp.metrics && !clearbitResp.domain));

const employees = (!clearbit_failed && clearbitResp.metrics && clearbitResp.metrics.employees) ? clearbitResp.metrics.employees : 0;
const industry = (!clearbit_failed && clearbitResp.category && clearbitResp.category.industry) ? clearbitResp.category.industry : 'Unknown';
const revenue = (!clearbit_failed && clearbitResp.metrics && clearbitResp.metrics.estimatedAnnualRevenue) ? clearbitResp.metrics.estimatedAnnualRevenue : 'Unknown';

return [{ json: {
  valid: lead.valid,
  lead_id: lead.lead_id,
  email: lead.email,
  name: lead.name,
  company: lead.company,
  role: lead.role,
  phone: lead.phone,
  problem_description: lead.problem_description,
  employees,
  industry,
  revenue,
  clearbit_failed
} }];

const lead = $('Check Clearbit Response and Set Enrichment').first().json;

const problem_fit_score = 5;
const fit_reasoning = 'LLM scoring unavailable; default score applied';
const llm_failed = true;

// Size score
const employees = lead.employees || 0;
let size_score = 0;
if (employees >= 500) size_score = 3;
else if (employees >= 50) size_score = 2;
else size_score = 1;

// Industry score
const highValueIndustries = ['Technology', 'Software', 'Financial Services', 'Healthcare', 'E-commerce', 'SaaS'];
const medValueIndustries = ['Manufacturing', 'Retail', 'Education', 'Professional Services'];
let industry_score = 0;
if (highValueIndustries.some(i => (lead.industry || '').includes(i))) industry_score = 3;
else if (medValueIndustries.some(i => (lead.industry || '').includes(i))) industry_score = 2;
else industry_score = 1;

const composite_score = (problem_fit_score * 0.5) + (size_score * 1.5) + (industry_score * 1.0);

let tier;
if (composite_score >= 10) tier = 'A';
else if (composite_score >= 6) tier = 'B';
else tier = 'C';

return [{ json: {
  lead_id: lead.lead_id,
  email: lead.email,
  name: lead.name,
  company: lead.company,
  role: lead.role,
  phone: lead.phone,
  problem_description: lead.problem_description,
  employees: lead.employees,
  industry: lead.industry,
  revenue: lead.revenue,
  clearbit_failed: lead.clearbit_failed || false,
  problem_fit_score,
  fit_reasoning,
  llm_failed,
  size_score,
  industry_score,
  composite_score,
  tier
} }];

const llmResp = $input.first().json;
const lead = $('Check Clearbit Response and Set Enrichment').first().json;

let problem_fit_score = 5;
let fit_reasoning = '';
let llm_failed = false;
let llm_parse_failed = false;

if (llmResp.choices && llmResp.choices.length > 0) {
  try {
    // Strip markdown code fences that some models add despite instructions
    const rawContent = llmResp.choices[0].message.content || '';
    const content = rawContent.replace(/```json\n?|```/g, '').trim();
    const parsed = JSON.parse(content);
    problem_fit_score = (parsed.problem_fit_score !== undefined) ? Number(parsed.problem_fit_score) : 5;
    fit_reasoning = parsed.fit_reasoning || '';
  } catch(e) {
    problem_fit_score = 5;
    fit_reasoning = 'Parse error; default applied';
    llm_failed = true;
    llm_parse_failed = true;
  }
}

// Size score
const employees = lead.employees || 0;
let size_score = 0;
if (employees >= 500) size_score = 3;
else if (employees >= 50) size_score = 2;
else size_score = 1;

// Industry score
const highValueIndustries = ['Technology', 'Software', 'Financial Services', 'Healthcare', 'E-commerce', 'SaaS'];
const medValueIndustries = ['Manufacturing', 'Retail', 'Education', 'Professional Services'];
let industry_score = 0;
if (highValueIndustries.some(i => (lead.industry || '').includes(i))) industry_score = 3;
else if (medValueIndustries.some(i => (lead.industry || '').includes(i))) industry_score = 2;
else industry_score = 1;

// Composite
const composite = (problem_fit_score * 0.5) + (size_score * 1.5) + (industry_score * 1.0);

let tier;
if (composite >= 10) tier = 'A';
else if (composite >= 6) tier = 'B';
else tier = 'C';

return [{ json: {
  lead_id: lead.lead_id,
  email: lead.email,
  name: lead.name,
  company: lead.company,
  role: lead.role,
  phone: lead.phone,
  problem_description: lead.problem_description,
  employees: lead.employees,
  industry: lead.industry,
  revenue: lead.revenue,
  clearbit_failed: lead.clearbit_failed || false,
  problem_fit_score,
  fit_reasoning,
  llm_failed,
  llm_parse_failed,
  size_score,
  industry_score,
  composite_score: composite,
  tier
} }];

let lead;
try {
  lead = $('Parse LLM Score and Compute Lead Tier').first().json;
} catch(e) {
  lead = $('Set Default Score After LLM Failure').first().json;
}
return [{ json: lead }];
